public class Person {

    // instance variables
    String name;
    int age;
    String gender;

    // constructor 构造器
    public Person(String name, int age, String gender) {
        this.name = name;
        this.age = age;
        this.gender = gender;
    }

    // method 方法
    public void speak() {
        System.out.println("nihao");
    }

    public static void main(String[] args) {
        Person p1 = new Person("zhangsan", 18, "male"); // 创建对象 p1
        p1.speak();  // 调用方法

        System.out.println(p1.name);
        System.out.println(p1.age);
        System.out.println(p1.gender);

        System.out.println(p1); // 打印对象引用地址（内存中的地址）
    }
}
